DELETE FROM core_visualization_linkage_field
WHERE linkage_id IN (
    SELECT id FROM (
        SELECT pvl.id
        FROM core_visualization_linkage pvl
        WHERE pvl.dv_id = #{dvId}

          AND pvl.source_view_id = #{sourceViewId}

    ) temp_table
)

DELETE FROM core_visualization_linkage_field_snapshot
WHERE linkage_id IN (
            SELECT id FROM (
                SELECT pvl.id
                FROM core_visualization_linkage_snapshot pvl
                WHERE pvl.dv_id = #{dvId}

                  AND pvl.source_view_id = #{sourceViewId}

            ) temp_table
        )
